V = t.TypeVar("V")

# The prompt functions to use.  The doc tools currently override these
# functions to customize how they work.
visible_prompt_func: t.Callable[[str], str] = input

_ansi_colors = {
    "black": 30,
    "red": 31,
    "green": 32,
    "yellow": 33,
    "blue": 34,
    "magenta": 35,
    "cyan": 36,
    "white": 37,
    "reset": 39,
    "bright_black": 90,
    "bright_red": 91,
    "bright_green": 92,
    "bright_yellow": 93,
    "bright_blue": 94,
    "bright_magenta": 95,
    "bright_cyan": 96,
    "bright_white": 97,
}
_ansi_reset_all = "\033[0m"


def hidden_prompt_func(prompt: str) -> str:
    """Prompt the user for input without echoing the input.

    This function wraps getpass.getpass to hide the user's input (for
    password prompts or similar). It accepts a prompt string and returns
    the entered value as a string.
    """
    import getpass

    return getpass.getpass(prompt)


def _build_prompt(
    text: str,
    suffix: str,
    show_default: bool = False,
    default: t.Any | None = None,
    show_choices: bool = True,
    type: ParamType | None = None,
) -> str:
    """Construct the prompt string to display to the user.

    This helper composes the base prompt text with optional choices and
    default value formatting, and appends the configured suffix.
    """
    prompt = text
    if type is not None and show_choices and isinstance(type, Choice):
        prompt += f" ({', '.join(map(str, type.choices))})"
    if default is not None and show_default:
        prompt = f"{prompt} [{_format_default(default)}]"
    return f"{prompt}{suffix}"


def _format_default(default: t.Any) -> t.Any:
    """Return a printable representation of a default value.

    If the default is a file-like object with a name attribute this
    returns the name so the prompt doesn't include the object repr.
    """
    if isinstance(default, (io.IOBase, LazyFile)) and hasattr(default, "name"):
        return default.name

    return default


def prompt(
    text: str,
    default: t.Any | None = None,
    hide_input: bool = False,
    confirmation_prompt: bool | str = False,
    type: ParamType | t.Any | None = None,
    value_proc: t.Callable[[str], t.Any] | None = None,
    prompt_suffix: str = ": ",
    show_default: bool = True,
    err: bool = False,
    show_choices: bool = True,
) -> t.Any:
    """Prompts a user for input.  This is a convenience function that can
    be used to prompt a user for input later.

    If the user aborts the input by sending an interrupt signal, this
    function will catch it and raise a :exc:`Abort` exception.

    :param text: the text to show for the prompt.
    :param default: the default value to use if no input happens.  If this
                    is not given it will prompt until it's aborted.
    :param hide_input: if this is set to true then the input value will
                       be hidden.
    :param confirmation_prompt: Prompt a second time to confirm the
        value. Can be set to a string instead of ``True`` to customize
        the message.
    :param type: the type to use to check the value against.
    :param value_proc: if this parameter is provided it's a function that
                       is invoked instead of the type conversion to
                       convert a value.
    :param prompt_suffix: a suffix that should be added to the prompt.
    :param show_default: shows or hides the default value in the prompt.
    :param err: if set to true the file defaults to ``stderr`` instead of
                ``stdout``, the same as with echo.
    :param show_choices: Show or hide choices if the passed type is a Choice.
    """
    prompt_func = hidden_prompt_func if hide_input else visible_prompt_func
    if value_proc is not None and type is not None:
        raise TypeError("only one of 'type' and 'value_proc' can be used")

    if isinstance(confirmation_prompt, str) and not confirmation_prompt:
        confirmation_prompt = True

    # Build the prompt
    if isinstance(type, ParamType):
        param_type = type
    else:
        param_type = None

    prompt_text = _build_prompt(
        text,
        prompt_suffix,
        show_default=show_default,
        default=default,
        show_choices=show_choices,
        type=param_type,
    )

    # The inner conversion function
    def convert(value: str) -> t.Any:
        if value_proc is not None:
            return value_proc(value)
        if param_type is not None:
            return convert_type(value, param_type, param_hint=None)
        return value

    try:
        while True:
            try:
                value = prompt_func(prompt_text)
            except (KeyboardInterrupt, EOFError):
                echo("", err=err)
                raise Abort()

            # If nothing was entered, return default if provided
            if not value and default is not None:
                return default

            try:
                rv = convert(value)
            except Exception as exc:
                echo(str(exc), err=err)
                continue

            # Confirmation prompt if requested
            if confirmation_prompt:
                if confirmation_prompt is True:
                    confirm_text = f"Repeat for confirmation{prompt_suffix}"
                else:
                    confirm_text = str(confirmation_prompt)
                try:
                    confirmation = prompt_func(confirm_text)
                except (KeyboardInterrupt, EOFError):
                    echo("", err=err)
                    raise Abort()
                if confirmation != value:
                    echo(_("Error: values do not match"), err=err)
                    continue

            return rv
    finally:
        # Ensure any buffered output is flushed
        try:
            sys.stderr.flush()
            sys.stdout.flush()
        except Exception:
            pass


def prompt_func(hide_input: bool = False) -> t.Callable[[str], str]:
    """Return the appropriate prompt function.

    When hide_input is true this will return a function that hides
    terminal input (for password prompts), otherwise it returns the
    regular visible prompt function (usually built on input()).
    """
    return hidden_prompt_func if hide_input else visible_prompt_func


@contextmanager
def progressbar(
    iterable: cabc.Iterable[V] | int | None = None,
    length: int | None = None,
    label: str | None = None,
    show_pos: bool = True,
    item_show_func: t.Callable[[V], str] | None = None,
    fill_char: str = "#",
    empty_char: str = "-",
    width: int = 30,
    file: t.TextIO | None = None,
):
    """A very small progressbar context manager for iterables.

    This simplified progressbar yields an iterator over the given iterable
    and prints basic progress information to the provided file (stdout by
    default). The implementation is intentionally lightweight and blocks
    around iteration updates.
    """
    if file is None:
        file = sys.stderr

    # If iterable is an int, create a range
    if isinstance(iterable, int):
        iterable = range(iterable)

    # Support passing only length
    if iterable is None and length is not None:
        iterable = range(length)

    if hasattr(iterable, "__len__"):
        total = len(iterable)  # type: ignore[arg-type]
    else:
        total = None

    if total is None and length is not None:
        total = length

    index = 0
    try:
        # Print initial label
        if label:
            echo(label, err=False, file=file)
        if iterable is None:
            # Nothing to iterate over, yield an empty generator
            yield iter(())
            return

        for item in iterable:  # type: ignore[assignment]
            yield item
            index += 1
            # Draw a simple bar
            if total:
                frac = index / total
                filled = int(round(width * frac))
                bar = fill_char * filled + empty_char * (width - filled)
                pos = f" {index}/{total}" if show_pos else ""
                item_str = f" {item_show_func(item)}" if (item_show_func and index) else ""
                line = f"[{bar}]{pos}{item_str}"
                # Carriage return to overwrite previous line
                file.write("\r" + strip_ansi(line))
                file.flush()
        # Final newline
        file.write("\n")
        file.flush()
    finally:
        # Ensure cursor is on new line
        try:
            file.write("\n")
            file.flush()
        except Exception:
            pass


def _interpret_color(color: t.Any) -> t.Optional[str]:
    """Interpret a color value into an ANSI color sequence.

    Accepts booleans, None, color names, and integers. Returns a string
    containing the ANSI color escape (e.g. '\x1b[31m') or None if no
    color should be used.
    """
    if color is None:
        return None
    if color is True:
        # Resolve default color setting from environment or global config
        color = resolve_color_default()
    # If numeric color code provided
    if isinstance(color, int):
        return f"\033[{color}m"
    # If a color name provided
    if isinstance(color, str):
        code = _ansi_colors.get(color.lower())
        if code is not None:
            return f"\033[{code}m"
        # Allow raw ANSI sequences
        if color.startswith("\033[") and color.endswith("m"):
            return color
    # Unknown color type, return None
    return None


def edit(
    text: str = "",
    editor: str | None = None,
    require_save: bool = True,
    extension: str | None = None,
) -> str | None:
    """Open a text editor for the user to edit input.

    The function writes the provided text to a temporary file, launches an
    editor (determined via the 'editor' argument or environment variables),
    and returns the edited text. If the editor exits without changing the
    file and require_save is True, None is returned to indicate no change.
    """
    if editor is None:
        editor = os.environ.get("VISUAL") or os.environ.get("EDITOR") or "vi"

    # Create temporary file
    suffix = f".{extension}" if extension else ""
    with tempfile.NamedTemporaryFile(suffix=suffix, delete=False, mode="w+", encoding="utf-8") as tf:
        name = tf.name
        tf.write(text)
        tf.flush()
        os.fsync(tf.fileno())

    try:
        # Launch editor
        try:
            args = shlex.split(editor)
        except Exception:
            args = [editor]
        args.append(name)
        ret = subprocess.call(args)
        if ret != 0:
            # Editing failed
            raise UsageError(f"Editor {editor!r} exited with code {ret}")
        # Read contents back
        with open(name, "r", encoding="utf-8") as tf:
            edited = tf.read()
        if require_save and edited == text:
            return None
        return edited
    finally:
        try:
            os.unlink(name)
        except Exception:
            pass


@contextmanager
def raw_terminal(file):
    """Context manager that yields a raw terminal file descriptor.

    This context manager attempts to set the terminal to raw mode for the
    duration of the context. On systems where raw mode is not available or
    the stream is not a tty, this yields the provided file unchanged.
    """
    # Attempt to use termios if available
    try:
        import termios
        import tty

        fd = file.fileno()
    except Exception:
        # Not a file descriptor or termios not available, just yield file
        yield file
        return

    if not isatty(fd):
        yield file
        return

    old_attrs = termios.tcgetattr(fd)
    try:
        tty.setraw(fd)
        yield file
    finally:
        try:
            termios.tcsetattr(fd, termios.TCSADRAIN, old_attrs)
        except Exception:
            pass